Here's an updated version of the BaseRepository class that allows for dynamic field searching:

```csharp
public abstract class BaseRepository<TEntity> : IRepository<TEntity> where TEntity : class
{
    private readonly DbContext _dbContext;
    private readonly DbSet<TEntity> _dbSet;

    protected BaseRepository(DbContext dbContext)
    {
        _dbContext = dbContext;
        _dbSet = dbContext.Set<TEntity>();
    }

    public virtual async Task<TEntity> GetByIdAsync(int id)
    {
        return await _dbSet.FindAsync(id);
    }

    public virtual async Task<IEnumerable<TEntity>> GetAllAsync()
    {
        return await _dbSet.ToListAsync();
    }

    public virtual async Task<IEnumerable<TEntity>> FindByAsync(Expression<Func<TEntity, bool>> predicate)
    {
        return await _dbSet.Where(predicate).ToListAsync();
    }

    public virtual async Task<IEnumerable<TEntity>> FindByDynamicAsync(string columnName, object value)
    {
        var parameter = Expression.Parameter(typeof(TEntity));
        var memberExpression = Expression.PropertyOrField(parameter, columnName);
        var lambdaExpression = Expression.Lambda<Func<TEntity, bool>>(Expression.Equal(memberExpression, Expression.Constant(value)), parameter);

        return await _dbSet.Where(lambdaExpression).ToListAsync();
    }

